body.raw:
{
  "model": "{{DEFAULT_CHAT_MODEL}}",
  "messages": [
    { "role": "system", "content": "You are a concise assistant." },
    { "role": "user",   "content": "Give me a one-sentence definition of a Postman collection." }
  ],
  "temperature": 0.7,
  "max_tokens": 200
}

{
  "model": "{{DEFAULT_CHAT_MODEL}}",
  "messages": [
    { "role": "user", "content": "Count from 1 to 5, one number per line." }
  ],
  "stream": true,
  "stream_options": { "include_usage": true }
}

{
  "model": "{{DEFAULT_CHAT_MODEL}}",
  "messages": [
    { "role": "user", "content": "What's the weather in Tokyo right now?" }
  ],
  "tools": [
    {
      "type": "function",
      "function": {
        "name": "get_current_weather",
        "description": "Fetch the current weather for a location.",
        "parameters": {
          "type": "object",
          "properties": {
            "location": { "type": "string", "description": "City and optional country, e.g. 'Tokyo, JP'." },
            "unit":     { "type": "string", "enum": ["celsius", "fahrenheit"], "default": "celsius" }
          },
          "required": ["location"],
          "additionalProperties": false
        }
      }
    }
  ],
  "tool_choice": "auto"
}

{
  "model": "{{DEFAULT_CHAT_MODEL}}",
  "messages": [
    {
      "role": "user",
      "content": [
        { "type": "text", "text": "Describe what's in this picture in one sentence." },
        {
          "type": "image_url",
          "image_url": {
            "url": "https://upload.wikimedia.org/wikipedia/commons/4/47/PNG_transparency_demonstration_1.png",
            "detail": "auto"
          }
        }
      ]
    }
  ]
}

{
  "model": "{{DEFAULT_CHAT_MODEL}}",
  "messages": [
    { "role": "system", "content": "Extract event details from the user message." },
    { "role": "user",   "content": "Team offsite on June 20, 2026 in Lisbon. RSVP by June 1." }
  ],
  "response_format": {
    "type": "json_schema",
    "json_schema": {
      "name": "event_extraction",
      "strict": true,
      "schema": {
        "type": "object",
        "properties": {
          "title":    { "type": "string" },
          "date":     { "type": "string", "description": "ISO 8601 date." },
          "location": { "type": "string" },
          "rsvp_by":  { "type": "string", "description": "ISO 8601 date." }
        },
        "required": ["title", "date", "location", "rsvp_by"],
        "additionalProperties": false
      }
    }
  }
}

{
  "model": "{{DEFAULT_EMBEDDING_MODEL}}",
  "input": [
    "Postman is an API platform.",
    "Embeddings turn text into vectors."
  ],
  "encoding_format": "float"
}

